def solve(graph, start):
    distances = {start: 0}
    queue = [start]
    index = 0
    while index < len(queue):
        node = queue[index]
        index += 1
        for neighbor in graph.get(node, []):
            if neighbor not in distances:
                distances[neighbor] = distances[node] + 1
                queue.append(neighbor)
    return distances

