from solution import solve

def test_breadth_first_distances():
    assert solve({'a': ['b', 'c'], 'b': ['d'], 'c': ['d']}, 'a') == {'a': 0, 'b': 1, 'c': 1, 'd': 2}

def test_start_not_in_graph():
    assert solve({}, 'x') == {'x': 0}
